INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05090', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「正因這個世界上往往會有不應得的不幸，甚至不應得的福樂發生，人類才必須一再的 為一己生命的存在重新做倫理的抉擇。同時什麼是我們的生存所以獲得意義之『道』， 也就不能繼續依賴我們的際遇的幸與不幸，而必須向每個人自己內心裡的『志』與『好』 去尋求其『輕』與『重』了。」下列敘述何者最符合本文意旨？', '["人類時常在人生際遇中改變「志好」的方向", "能終其一生貫徹「志好」是最幸福的一件事", "人生的意義決定於對「志好」的認同與追求", "倫理與「志好」經常是兩個互相衝突的選項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05091', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「有時不期然而遇見來巡視的主治大夫。以前，他仔細為我講解父親的病況與治療方式； 其後，我們漫談著一些死生問題及形上哲學；最近，他往往只是悲憫地陪我望著病床上 只餘半身的父親，口中喃喃著：『怎麼辦？怎麼辦？』怎麼辦呢？而父親總是沉沉地睡， 沒有春夏秋冬，沒有悲歡哀樂。我輕輕撫摸那一頭白髮。不免自問：當時我們為他所做 的抉擇是對的嗎？現在父親若能睜開眼睛說話，他會對我們說甚麼呢？」下列選項與此 段文字無關的是：', '["生命總是有盡頭", "父女之情難以割捨", "醫生亦難掌握生死", "生死決定總叫人猶疑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05092', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我生平不大服膺『開卷有益』這句古訓，這叫人對文字起近乎迷信的崇敬，是不妥當 的。尤其近世印刷發達，印成書的形式而並不算得是書的東西，真是汗牛充棟，我們要 昧了天良，才能勸人相信『開卷有益』這句話中確有至理。」 下列選項何者最貼近本文意旨？', '["印刷術發達，書籍取得變得容易，讀書卻變得無用了", "市面上充斥太多徒具書的形式而不配稱為書的印刷品", "書籍氾濫，資訊爆炸，反而容易蠱惑人心，讓人迷失", "從古至今，「開卷有益」這句古訓都完全不具說服力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05093', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項，何者有「得力助手」的意思？', '["股肱耳目", "肝膽相照", "手足情深", "心腹之交"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05094', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列各組文句「」中的字，詞義完全相同的是：', '["平原君乃免「冠」謝，固留公子 ／名「冠」諸侯，不虛耳", "敬「孫」務時敏，厥脩乃來／近之則不「孫」，遠之則怨", "視弟子與臣若其身，「惡」施不慈 ／惡得不禁「惡」而勸愛", "河南程氏兩夫子出，而有以接乎孟氏之「傳」 ／於是作為「傳」義以發其意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05095', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「大哉居乎移氣移體  慎其獨也潤屋潤身」，此副對聯適合用於何種祝賀場合？', '["壽誕", "喬遷", "升職", "生子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05096', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '夫學者載籍極博，猶考信於六藝。詩書雖缺，然虞夏之文可知也。堯將遜位，讓於 虞舜；舜禹之閒，岳牧咸薦，乃試之於位，典職數十年，功用既興，然後授政。示 天下重器，王者大統，傳天下若斯之難也。而說者曰堯讓天下於許由，許由不受， 恥之逃隱。及夏之時，有卞隨、務光者。此何以稱焉？（《史記‧伯夷列傳》） 下列選項，何者最接近本段文字的主旨？', '["許由等人不受天下的傳說可疑", "堯舜禪讓的古史傳說不可盡信", "許由等人展現淡泊名利的節操", "堯舜禪讓不是最佳的政治制度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05097', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「語時事則指而可想，論懷抱則曠而且真。加以貞志不休，安道苦節，不以躬耕為 恥，不以無財為病，自非大賢篤志，與道污隆，孰能如此乎？」 依據上文，下列選項所指作家何者正確？', '["屈原", "陶潛", "杜甫", "蘇軾"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05098', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「□□□□採用明朝紀年，並且頻頻引入歷史人物和歷史事件……就其視野而言， □□□□是富於預見性的，但小說的敘述卻是以作者的個人經歷和對當下生活的個 人觀察為基礎。小說淋漓盡致地展現了文人道德的淪喪、政府體制的窘境……他為 這些五花八門的人物角色的虛妄、蠢行和枉費心機的企圖勾勒出一幅幅辛辣的譏諷 肖像」 上文空缺處應填入的選項是：', '["老殘遊記", "新石頭記", "聊齋誌異", "儒林外史"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05099', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項，何者沒有悠然自適的意涵？', '["一路經行處，莓苔見屐痕。白雲依靜渚，春草閉閒門。過雨看松色，隨山到水源。 溪花與禪意，相對亦忘言", "獸樂在山谷，魚樂在陂池。蟲樂在深草，鳥樂在高枝。所樂雖不同，同歸適其宜。 不以彼易此，況論是與非", "玉壺繫青絲，沽酒來何遲。山花向我笑，正好銜杯時。晚酌東窗下，流鶯復在茲。 春風與醉客，今日乃相宜", "御氣雲樓敞，含風綵仗高。仙人張內樂，王母獻宮桃。羅襪紅蕖豔，金羈白雪毛。 舞階銜壽酒，走索背秋毫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
